20	/// Standard transformer sinusoidal positional encoding table.
21	///
22	/// `sinusoidal_encoding(seq_len, d_model)` returns a deterministic
23	/// `[seq_len, d_model]` table labeled `[time, dim]`:
24	///
25	/// - even cols `2i`:   `sin(pos / 10000^(2i / d_model))`
26	/// - odd cols `2i+1`:  `cos(pos / 10000^(2i / d_model))`
27	///
28	/// Pure -- no params, no seed. The `[time, dim]` labels propagate
29	/// through element-wise add when paired with a token embedding
30	/// output of matching shape.
31	fn builtin_sinusoidal_encoding(
32	    name: &str,
33	    args: Vec<DenseArray>,
34	) -> Result<DenseArray, RuntimeError> {
35	    let (t, d) = parse_sinusoidal_args(name, &args)?;
36	    let mut data = vec![0.0_f64; t * d];
37	    for pos in 0..t {
38	        for col in 0..d {
39	            let exponent = (2 * (col / 2)) as f64 / d as f64;
40	            let theta = pos as f64 / 10000.0_f64.powf(exponent);
41	            data[pos * d + col] = if col % 2 == 0 {
42	                theta.sin()
43	            } else {
44	                theta.cos()
45	            };
46	        }
47	    }
48	    let arr = DenseArray::new(Shape::new(vec![t, d]), data)?;
49	    Ok(arr.with_labels(vec![Some("time".into()), Some("dim".into())])?)
