1	//! Op enums and forward/backward helpers for autograd nodes.
2	
3	use mlpl_array::DenseArray;
4	
5	/// Unary elementwise op.
6	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
7	pub enum UnaryOp {
8	    /// -x
9	    Neg,
10	    /// exp(x)
11	    Exp,
12	    /// natural log
13	    Log,
14	    /// max(0, x)
15	    Relu,
16	    /// tanh(x)
17	    Tanh,
18	    /// 1 / (1 + exp(-x))
19	    Sigmoid,
20	}
21	
22	/// Binary elementwise op.
23	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
24	pub enum BinaryOp {
25	    /// a + b
26	    Add,
27	    /// a - b
28	    Sub,
29	    /// a * b
30	    Mul,
31	    /// a / b
32	    Div,
33	}
34	
35	impl UnaryOp {
36	    /// Forward pass: apply the op elementwise.
37	    #[must_use]
38	    pub fn forward(self, x: &DenseArray) -> DenseArray {
39	        let f: fn(f64) -> f64 = match self {
40	            Self::Neg => |v| -v,
41	            Self::Exp => f64::exp,
42	            Self::Log => f64::ln,
43	            Self::Relu => |v| v.max(0.0),
44	            Self::Tanh => f64::tanh,
45	            Self::Sigmoid => |v| 1.0 / (1.0 + (-v).exp()),
46	        };
47	        x.map(f)
48	    }
49	
50	    /// Compute local gradient wrt input x given upstream gradient.
51	    ///
52	    /// `x` is the parent input; `y` is the forward output (cached).
53	    #[must_use]
54	    pub fn backward(self, x: &DenseArray, y: &DenseArray, upstream: &DenseArray) -> DenseArray {
55	        let n = upstream.data().len();
56	        let mut out = Vec::with_capacity(n);
57	        for i in 0..n {
58	            let xi = x.data()[i];
59	            let yi = y.data()[i];
60	            let g = upstream.data()[i];
61	            let local = match self {
62	                Self::Neg => -1.0,
63	                Self::Exp => yi,
64	                Self::Log => 1.0 / xi,
65	                Self::Relu => {
66	                    if xi > 0.0 {
67	                        1.0
68	                    } else {
69	                        0.0
70	                    }
71	                }
72	                Self::Tanh => 1.0 - yi * yi,
73	                Self::Sigmoid => yi * (1.0 - yi),
74	            };
75	            out.push(g * local);
76	        }
77	        DenseArray::new(upstream.shape().clone(), out).expect("shape preserved")
78	    }
79	}
80	
81	impl BinaryOp {
82	    /// Forward pass with scalar broadcasting.
83	    pub fn forward(
84	        self,
85	        a: &DenseArray,
86	        b: &DenseArray,
87	    ) -> Result<DenseArray, mlpl_array::ArrayError> {
88	        let op: fn(f64, f64) -> f64 = match self {
89	            Self::Add => |x, y| x + y,
90	            Self::Sub => |x, y| x - y,
91	            Self::Mul => |x, y| x * y,
92	            Self::Div => |x, y| x / y,
93	        };
94	        a.apply_binop(b, op)
95	    }
96	
97	    /// Compute upstream gradients for the two parents.
98	    ///
99	    /// Returns `(grad_a, grad_b)`, each shaped like the upstream grad
100	    /// (caller is responsible for un-broadcasting to the parent shape).
101	    #[must_use]
102	    pub fn backward(
103	        self,
104	        a_val: &DenseArray,
105	        b_val: &DenseArray,
106	        upstream: &DenseArray,
107	    ) -> (DenseArray, DenseArray) {
108	        let n = upstream.data().len();
109	        let mut ga = Vec::with_capacity(n);
110	        let mut gb = Vec::with_capacity(n);
111	        for i in 0..n {
112	            let g = upstream.data()[i];
113	            // Index parents by broadcast: scalars reuse index 0.
114	            let ai = if a_val.data().len() == 1 {
115	                a_val.data()[0]
116	            } else {
117	                a_val.data()[i]
118	            };
119	            let bi = if b_val.data().len() == 1 {
120	                b_val.data()[0]
121	            } else {
122	                b_val.data()[i]
123	            };
124	            match self {
125	                Self::Add => {
126	                    ga.push(g);
127	                    gb.push(g);
128	                }
129	                Self::Sub => {
130	                    ga.push(g);
131	                    gb.push(-g);
132	                }
133	                Self::Mul => {
134	                    ga.push(g * bi);
135	                    gb.push(g * ai);
136	                }
137	                Self::Div => {
138	                    ga.push(g / bi);
139	                    gb.push(-g * ai / (bi * bi));
140	                }
141	            }
142	        }
143	        let shape = upstream.shape().clone();
144	        (
145	            DenseArray::new(shape.clone(), ga).expect("shape"),
146	            DenseArray::new(shape, gb).expect("shape"),
147	        )
148	    }
149	}
