151	/// Numerically-stable softmax along `axis`, supports rank-1 and rank-2.
152	#[must_use]
153	pub fn softmax_forward(x: &DenseArray, axis: usize) -> DenseArray {
154	    let row = |r: &[f64]| -> Vec<f64> {
155	        let m = r.iter().copied().fold(f64::NEG_INFINITY, f64::max);
156	        let exps: Vec<f64> = r.iter().map(|v| (v - m).exp()).collect();
157	        let s: f64 = exps.iter().sum();
158	        exps.into_iter().map(|e| e / s).collect()
