168	                for r in 0..rows {
169	                    let sm = row(&x.data()[r * cols..(r + 1) * cols]);
170	                    out[r * cols..(r + 1) * cols].copy_from_slice(&sm);
171	                }
172	            } else {
173	                for c in 0..cols {
174	                    let col: Vec<f64> = (0..rows).map(|r| x.data()[r * cols + c]).collect();
175	                    let sm = row(&col);
176	                    for (r, v) in sm.iter().enumerate() {
