1	//! The `grad(expr, wrt)` built-in: reverse-mode autograd over
2	//! a tree-walked mini-evaluator that lifts array-valued operations
3	//! onto an autograd tape.
4	
5	use std::collections::HashMap;
6	use std::rc::Rc;
7	
8	use mlpl_array::{DenseArray, Shape};
9	use mlpl_autograd::{Tape, Tensor};
10	use mlpl_core::Span;
11	use mlpl_parser::{BinOpKind, Expr};
12	
13	use crate::env::Environment;
14	use crate::error::EvalError;
15	
16	/// Evaluate a `grad(expr, wrt)` call and return the gradient array of
17	/// the scalar expression `expr` with respect to the parameter `wrt`.
18	pub(crate) fn eval_grad(args: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
19	    if args.len() != 2 {
20	        return Err(EvalError::BadArity {
21	            func: "grad".into(),
22	            expected: 2,
23	            got: args.len(),
24	        });
25	    }
26	    let wrt_name = match &args[1] {
27	        Expr::Ident(n, _) => n.clone(),
28	        _ => {
29	            return Err(EvalError::Unsupported(
30	                "grad: second argument must be a parameter identifier".into(),
31	            ));
32	        }
33	    };
34	    if !env.is_param(&wrt_name) {
35	        return Err(EvalError::Unsupported(format!(
36	            "grad: '{wrt_name}' is not a tracked parameter"
37	        )));
38	    }
39	    let tape = Tape::new();
40	    let mut params: HashMap<String, Tensor> = HashMap::new();
41	    for (name, value) in env.params() {
42	        params.insert(name.clone(), Tensor::param(Rc::clone(&tape), value.clone()));
43	    }
44	    let root = eval_tensor_expr(&args[0], env, &tape, &params)?;
45	    root.backward();
46	    let wrt_tensor = params
47	        .get(&wrt_name)
48	        .expect("wrt param present in params map");
49	    Ok(wrt_tensor
50	        .grad()
51	        .unwrap_or_else(|| DenseArray::zeros(wrt_tensor.value().shape().clone())))
52	}
53	
54	fn eval_tensor_expr(
55	    expr: &Expr,
56	    env: &mut Environment,
57	    tape: &Rc<Tape>,
58	    params: &HashMap<String, Tensor>,
59	) -> Result<Tensor, EvalError> {
60	    let leaf = |v: DenseArray| Tensor::leaf(Rc::clone(tape), v, false);
61	    match expr {
62	        Expr::IntLit(n, _) => Ok(leaf(DenseArray::from_scalar(*n as f64))),
63	        Expr::FloatLit(f, _) => Ok(leaf(DenseArray::from_scalar(*f))),
64	        Expr::Ident(name, _) => {
65	            if let Some(t) = params.get(name) {
66	                return Ok(t.clone());
67	            }
68	            let arr = env
69	                .get(name)
70	                .cloned()
71	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
72	            Ok(leaf(arr))
73	        }
74	        Expr::ArrayLit(elems, _) => {
75	            let arr = crate::eval_ops::eval_array_lit(elems, env, &mut None)?;
76	            Ok(leaf(arr))
77	        }
78	        Expr::UnaryNeg { operand, .. } => Ok(eval_tensor_expr(operand, env, tape, params)?.neg()),
79	        Expr::BinOp { op, lhs, rhs, .. } => {
80	            let l = eval_tensor_expr(lhs, env, tape, params)?;
81	            let r = eval_tensor_expr(rhs, env, tape, params)?;
82	            Ok(match op {
83	                BinOpKind::Add => l.add(&r),
84	                BinOpKind::Sub => l.sub(&r),
85	                BinOpKind::Mul => l.mul(&r),
86	                BinOpKind::Div => l.div(&r),
87	            })
88	        }
89	        Expr::FnCall { name, args, .. } => eval_tensor_fncall(name, args, env, tape, params),
90	        Expr::TensorCtor { shape, .. } => {
91	            let dims = eval_shape_dims(shape, env)?;
92	            Ok(leaf(DenseArray::zeros(Shape::new(dims))))
93	        }
94	        Expr::Assign { .. }
95	        | Expr::Repeat { .. }
96	        | Expr::Train { .. }
97	        | Expr::For { .. }
98	        | Expr::Experiment { .. }
99	        | Expr::StrLit(_, _) => Err(EvalError::Unsupported(
100	            "grad: expression form not supported inside grad()".into(),
101	        )),
102	    }
103	}
104	
105	fn eval_tensor_fncall(
106	    name: &str,
107	    args: &[Expr],
108	    env: &mut Environment,
109	    tape: &Rc<Tape>,
110	    params: &HashMap<String, Tensor>,
111	) -> Result<Tensor, EvalError> {
112	    let arity = |expected: usize| -> Result<(), EvalError> {
113	        if args.len() == expected {
114	            Ok(())
115	        } else {
116	            Err(EvalError::BadArity {
117	                func: name.into(),
118	                expected,
119	                got: args.len(),
120	            })
121	        }
122	    };
123	    if let Some(op) = unary_tensor_op(name) {
124	        arity(1)?;
125	        let a = eval_tensor_expr(&args[0], env, tape, params)?;
126	        return Ok(op(&a));
127	    }
128	    if name == "matmul" {
129	        arity(2)?;
130	        let a = eval_tensor_expr(&args[0], env, tape, params)?;
131	        let b = eval_tensor_expr(&args[1], env, tape, params)?;
132	        return Ok(a.matmul(&b));
133	    }
134	    if name == "apply" {
135	        arity(2)?;
136	        let model_name = match &args[0] {
137	            Expr::Ident(n, _) => n.clone(),
138	            _ => {
139	                return Err(EvalError::Unsupported(
140	                    "grad: apply's first argument must be a model identifier".into(),
141	                ));
142	            }
143	        };
144	        let model = env
145	            .get_model(&model_name)
146	            .cloned()
147	            .ok_or(EvalError::UndefinedVariable(model_name))?;
148	        let x = eval_tensor_expr(&args[1], env, tape, params)?;
149	        return crate::model_tape::apply_model_tape(&model, x, tape, params);
150	    }
151	    Err(EvalError::Unsupported(format!(
152	        "grad: function '{name}' not supported inside grad()"
153	    )))
154	}
155	
156	fn unary_tensor_op(name: &str) -> Option<fn(&Tensor) -> Tensor> {
157	    Some(match name {
158	        "sum" => Tensor::sum,
159	        "mean" => Tensor::mean,
160	        "exp" => Tensor::exp,
161	        "log" => Tensor::log,
162	        "relu" => Tensor::relu,
163	        "tanh" => Tensor::tanh,
164	        "sigmoid" => Tensor::sigmoid,
165	        "softmax" => Tensor::softmax,
166	        "transpose" => Tensor::transpose,
167	        _ => return None,
168	    })
169	}
170	
171	fn eval_shape_dims(shape: &[Expr], env: &mut Environment) -> Result<Vec<usize>, EvalError> {
172	    let mut dims = Vec::with_capacity(shape.len());
173	    for dim_expr in shape {
174	        let arr = crate::eval::eval_expr(dim_expr, env, &mut None)?.into_array()?;
175	        if arr.rank() != 0 {
176	            return Err(EvalError::InvalidShapeDim);
177	        }
178	        let v = arr.data()[0];
179	        if v < 0.0 || v.fract() != 0.0 {
180	            return Err(EvalError::InvalidShapeDim);
181	        }
182	        dims.push(v as usize);
183	    }
184	    Ok(dims)
185	}
186	// ----- optimizer state and built-in dispatch (Saga 10) -----
187	//
188	// Saga 10 design choice: optimizer state lives on `Environment` as a
189	// map keyed by `(optimizer_name, param_name, slot_name)` instead of
190	// in a new crate. The `mlpl-autograd` substrate already lives in its
191	// own crate, and Adam / momentum-SGD are thin wrappers around `grad`
192	// plus per-param buffers, so a fresh crate would just trampoline
193	// through `mlpl-eval` to reach `Environment`. Folding the state and
194	// dispatch hooks into `grad.rs` keeps the wiring local and respects
195	// the project's per-module function-count budget.
196	//
197	// Step 001 adds only the storage type and stub built-in dispatch.
198	// Steps 002 and 003 fill in `momentum_sgd` and `adam`.
199	
200	/// Per-optimizer, per-parameter state buffers (e.g. momentum velocity,
201	/// Adam first/second moments).
202	///
203	/// Step 001 exposes the storage as plain public fields keyed by
204	/// `(optimizer_name, param_name, slot_name)` so steps 002 and 003 can
205	/// fill in `momentum_sgd` and `adam` without dragging extra accessor
206	/// helpers across the per-module function-count budget.
207	#[derive(Clone, Debug, Default)]
208	pub struct OptimizerState {
209	    /// Buffers keyed by `(optimizer_name, param_name, slot_name)`.
210	    /// `slot_name` lets a single optimizer store multiple buffers per
211	    /// param (e.g. Adam needs both `m` and `v`).
212	    pub buffers: HashMap<(String, String, String), DenseArray>,
213	    /// Per-optimizer step counter (for Adam bias correction).
214	    pub steps: HashMap<String, u64>,
215	}
216	
217	/// Read-only accessor used by tests and downstream optimizer code.
218	#[must_use]
219	pub fn optim_state(env: &Environment) -> &OptimizerState {
220	    &env.optim_state
221	}
222	
223	/// Mutable accessor used by tests and downstream optimizer code.
224	pub fn optim_state_mut(env: &mut Environment) -> &mut OptimizerState {
225	    &mut env.optim_state
226	}
227	
228	/// `momentum_sgd(loss_expr, params, lr, beta)` built-in.
229	///
230	/// `params` is either a single param identifier or an array literal of
231	/// param identifiers. For each param `w`, applies the classical
232	/// heavy-ball update with per-param velocity buffer `v` stored on the
233	/// environment under `("momentum_sgd", w, "v")`:
234	///
235	/// ```text
236	///     g       = grad(loss_expr, w)
237	///     v_new   = beta * v_old + g
238	///     w_new   = w - lr * v_new
239	/// ```
240	///
241	/// Returns a scalar zero (the call is invoked for its side effects on
242	/// the parameter bindings and optimizer state).
243	/// Resolve the optimizer's `params` argument into a flat list of
244	/// parameter identifiers. Accepts:
245	///
246	/// - a single param identifier: `adam(loss, W, ...)`
247	/// - an array literal of param identifiers: `adam(loss, [W, b], ...)`
248	/// - a model identifier registered via the Saga 11 model DSL:
249	///   `adam(loss, M, ...)` walks `ModelSpec::params()` and returns its
250	///   flat, order-stable parameter list.
251	fn collect_params(arg: &Expr, env: &Environment, func: &str) -> Result<Vec<String>, EvalError> {
252	    match arg {
253	        Expr::Ident(n, _) => {
254	            if let Some(model) = env.get_model(n) {
