364	///     g     = grad(loss_expr, w)
365	///     m     = b1*m + (1 - b1)*g
366	///     v     = b2*v + (1 - b2)*g*g
367	///     mhat  = m / (1 - b1^t)
368	///     vhat  = v / (1 - b2^t)
369	///     w     = w - lr * mhat / (sqrt(vhat) + eps)
370	/// ```
371	pub(crate) fn eval_adam(args: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
372	    if args.len() != 6 {
373	        return Err(EvalError::BadArity {
374	            func: "adam".into(),
375	            expected: 6,
376	            got: args.len(),
377	        });
378	    }
379	    let loss_expr = args[0].clone();
380	    let param_names = collect_params(&args[1], env, "adam")?;
381	    let scalar_arg = |expr: &Expr, env: &mut Environment| -> Result<f64, EvalError> {
382	        let arr = crate::eval::eval_expr(expr, env, &mut None)?.into_array()?;
383	        if arr.rank() != 0 {
