395	    // Step counter is 1-based: bump first, then read.
396	    let t = {
397	        let entry = env.optim_state.steps.entry("adam".into()).or_insert(0);
398	        *entry += 1;
399	        *entry
400	    };
401	    let bc1 = 1.0 - b1.powi(t as i32);
402	    let bc2 = 1.0 - b2.powi(t as i32);
