435	            .data()
436	            .iter()
437	            .zip(g.data().iter())
438	            .map(|(mo, gv)| b1 * mo + (1.0 - b1) * gv)
439	            .collect();
440	        let v_data: Vec<f64> = v_old
441	            .data()
442	            .iter()
