//! Fused log-softmax + negative-log-likelihood loss for Saga 13.
//!
//! Cross-entropy is implemented as a single tape primitive rather than
//! a composition of `log`, `exp`, `softmax`, and a gather op. The
//! fused form keeps the forward pass numerically stable (log-sum-exp
//! with max-subtraction) and produces a tidy analytic gradient --
//! `(softmax(logits) - one_hot(targets)) / N` -- so we avoid
//! introducing a `gather` tape node just to back-propagate through
//! one.

use std::rc::Rc;

use mlpl_array::{DenseArray, Shape};

use crate::tape::{NodeData, NodeKind};
use crate::tensor::Tensor;

/// Forward pass: scalar mean NLL loss.
///
/// `logits` is `[N, V]` (caller is responsible for pre-flattening any
/// rank-3 `[B, T, V]` input to `[B*T, V]`). `targets` has length `N`
/// and contains class indices in `0..V`.
pub(crate) fn cross_entropy_forward(
    logits: &DenseArray,
    targets: &[usize],
) -> Result<DenseArray, String> {
    let (n, v) = split_rows_cols(logits)?;
    if targets.len() != n {
        return Err(format!(
            "cross_entropy: target length {} does not match logits rows {}",
            targets.len(),
            n
        ));
    }
    let data = logits.data();
    let mut total = 0.0;
    for (i, &t) in targets.iter().enumerate() {
        if t >= v {
            return Err(format!(
                "cross_entropy: target index {t} out of range for V={v}"
            ));
        }
        let row = &data[i * v..(i + 1) * v];
        let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
        let lse: f64 = m + row.iter().map(|x| (x - m).exp()).sum::<f64>().ln();
        total += lse - row[t];
    }
    Ok(DenseArray::from_scalar(total / n as f64))
}

/// Backward pass: gradient wrt `logits` given upstream scalar `g`.
///
/// Shape of the result matches `logits.shape()` exactly.
pub(crate) fn cross_entropy_backward(
    logits: &DenseArray,
    targets: &[usize],
    upstream_scalar: f64,
) -> DenseArray {
    let (n, v) = split_rows_cols(logits).expect("forward validated shape");
    let data = logits.data();
    let mut out = vec![0.0; data.len()];
    let inv_n = 1.0 / n as f64;
    for (i, &t) in targets.iter().enumerate() {
        let row = &data[i * v..(i + 1) * v];
        let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
        let exps: Vec<f64> = row.iter().map(|x| (x - m).exp()).collect();
        let s: f64 = exps.iter().sum();
        for (j, e) in exps.iter().enumerate() {
            let p = e / s;
            let indicator = if j == t { 1.0 } else { 0.0 };
            out[i * v + j] = upstream_scalar * (p - indicator) * inv_n;
        }
    }
    DenseArray::new(logits.shape().clone(), out).expect("shape preserved")
}

fn split_rows_cols(logits: &DenseArray) -> Result<(usize, usize), String> {
    let dims = logits.shape().dims();
    match dims.len() {
        2 => Ok((dims[0], dims[1])),
        3 => Ok((dims[0] * dims[1], dims[2])),
        r => Err(format!(
            "cross_entropy: logits must be rank 2 or 3, got rank {r}"
        )),
    }
}

impl Tensor {
    /// Fused cross-entropy loss.
    ///
    /// `targets` is consumed because it is stored on the tape node
    /// verbatim for the backward pass. Caller guarantees it contains
    /// valid `0..V` indices for the logits' trailing dimension.
    #[must_use]
    pub fn cross_entropy(&self, targets: Vec<usize>) -> Self {
        let logits = self.value();
        let value = cross_entropy_forward(&logits, &targets)
            .expect("caller validated shapes and indices");
        let _ = Shape::scalar();
        let node = self.tape.push(NodeData {
            value,
            grad: None,
            kind: NodeKind::CrossEntropy {
                logits: self.node,
                targets,
            },
            requires_grad: false,
        });
        Tensor {
            node,
            tape: Rc::clone(&self.tape),
        }
    }
}

