/// Validate logits / targets shapes and convert targets into a flat
/// `Vec<usize>`. Returns `(N, V, indices)` on success.
fn cross_entropy_indices(
    name: &str,
    logits: &DenseArray,
    targets: &DenseArray,
) -> Result<(usize, usize, Vec<usize>), RuntimeError> {
