    env.set("L".into(), arr(vec![2, 2, 3], data.clone()));
    env.set("T".into(), arr(vec![2, 2], vec![0.0, 1.0, 2.0, 1.0]));
    let out = run("cross_entropy(L, T)", &mut env);
    assert_eq!(out.rank(), 0);

    // Flattened [B*T, V] = [4, 3] with targets [0, 1, 2, 1]. The two
