    let flat = run("cross_entropy(L, T)", &mut env2);
    let a = out.data()[0];
    let b = flat.data()[0];
    assert!(
        (a - b).abs() < 1e-12,
        "rank-3 and rank-2 flattened forms disagree: {a} vs {b}"
    );
}

