7	/// Dispatch ML built-ins. Returns None if not matched.
8	pub(crate) fn try_call(
9	    name: &str,
10	    args: Vec<DenseArray>,
11	) -> Option<Result<DenseArray, RuntimeError>> {
12	    match name {
13	        "softmax" => Some(builtin_softmax(name, args)),
14	        "one_hot" => Some(builtin_one_hot(name, args)),
15	        "sinusoidal_encoding" => Some(builtin_sinusoidal_encoding(name, args)),
16	        "cross_entropy" => Some(builtin_cross_entropy(name, args)),
17	        _ => None,
18	    }
19	}
20	
21	/// `cross_entropy(logits, targets)` fused log-softmax + NLL, scalar mean.
22	///
23	/// Logits are `[N, V]` or `[B, T, V]` float; targets are `[N]` or
24	/// `[B, T]` integer-valued (represented as f64 with whole-number
25	/// values, the convention MLPL uses for all integer-typed builtins).
26	/// Errors surface as `InvalidArgument` with the reason string; the
27	/// `mlpl-eval` layer maps them to `EvalError::ShapeMismatch` where
28	/// appropriate.
29	fn builtin_cross_entropy(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
30	    if args.len() != 2 {
31	        return Err(RuntimeError::ArityMismatch {
32	            func: name.into(),
33	            expected: 2,
34	            got: args.len(),
35	        });
36	    }
37	    let (n, v, idx) = cross_entropy_indices(name, &args[0], &args[1])?;
38	    let data = args[0].data();
39	    let mut total = 0.0;
40	    for (i, &t) in idx.iter().enumerate() {
41	        let row = &data[i * v..(i + 1) * v];
42	        let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
43	        let lse: f64 = m + row.iter().map(|x| (x - m).exp()).sum::<f64>().ln();
44	        total += lse - row[t];
45	    }
46	    Ok(DenseArray::from_scalar(total / n as f64))
47	}
48	
49	/// Validate logits / targets shapes and convert targets into a flat
50	/// `Vec<usize>`. Returns `(N, V, indices)` on success.
51	fn cross_entropy_indices(
52	    name: &str,
53	    logits: &DenseArray,
54	    targets: &DenseArray,
55	) -> Result<(usize, usize, Vec<usize>), RuntimeError> {
56	    let dims = logits.shape().dims();
57	    let (n, v) = match dims.len() {
58	        2 => (dims[0], dims[1]),
59	        3 => (dims[0] * dims[1], dims[2]),
60	        r => {
61	            return Err(RuntimeError::InvalidArgument {
62	                func: name.into(),
63	                reason: format!("logits must be rank 2 or 3, got rank {r}"),
64	            });
65	        }
66	    };
67	    if targets.elem_count() != n {
68	        return Err(RuntimeError::InvalidArgument {
69	            func: name.into(),
70	            reason: format!(
71	                "targets must have {n} elements to match logits rows, got {}",
72	                targets.elem_count()
73	            ),
74	        });
75	    }
76	    let mut idx = Vec::with_capacity(n);
77	    for (i, &t) in targets.data().iter().enumerate() {
78	        if t < 0.0 || t.fract() != 0.0 {
79	            return Err(RuntimeError::InvalidArgument {
80	                func: name.into(),
81	                reason: format!("target[{i}] must be a non-negative integer, got {t}"),
82	            });
83	        }
84	        let ti = t as usize;
85	        if ti >= v {
86	            return Err(RuntimeError::InvalidArgument {
87	                func: name.into(),
88	                reason: format!("target[{i}] = {ti} out of range for V = {v}"),
89	            });
90	        }
91	        idx.push(ti);
92	    }
93	    Ok((n, v, idx))
94	}
