96	/// Standard transformer sinusoidal positional encoding table.
97	///
98	/// `sinusoidal_encoding(seq_len, d_model)` returns a deterministic
99	/// `[seq_len, d_model]` table labeled `[time, dim]`:
100	///
101	/// - even cols `2i`:   `sin(pos / 10000^(2i / d_model))`
102	/// - odd cols `2i+1`:  `cos(pos / 10000^(2i / d_model))`
103	///
104	/// Pure -- no params, no seed. The `[time, dim]` labels propagate
105	/// through element-wise add when paired with a token embedding
106	/// output of matching shape.
107	fn builtin_sinusoidal_encoding(
108	    name: &str,
109	    args: Vec<DenseArray>,
110	) -> Result<DenseArray, RuntimeError> {
111	    let (t, d) = parse_sinusoidal_args(name, &args)?;
112	    let mut data = vec![0.0_f64; t * d];
113	    for pos in 0..t {
114	        for col in 0..d {
115	            let exponent = (2 * (col / 2)) as f64 / d as f64;
116	            let theta = pos as f64 / 10000.0_f64.powf(exponent);
117	            data[pos * d + col] = if col % 2 == 0 {
118	                theta.sin()
119	            } else {
120	                theta.cos()
121	            };
122	        }
123	    }
124	    let arr = DenseArray::new(Shape::new(vec![t, d]), data)?;
125	    Ok(arr.with_labels(vec![Some("time".into()), Some("dim".into())])?)
126	}
127	
128	fn parse_sinusoidal_args(name: &str, args: &[DenseArray]) -> Result<(usize, usize), RuntimeError> {
129	    if args.len() != 2 {
130	        return Err(RuntimeError::ArityMismatch {
131	            func: name.into(),
132	            expected: 2,
133	            got: args.len(),
134	        });
135	    }
136	    for (i, a) in args.iter().enumerate() {
137	        if a.rank() != 0 {
138	            return Err(RuntimeError::InvalidArgument {
139	                func: name.into(),
140	                reason: format!("argument {i} must be a scalar, got rank {}", a.rank()),
141	            });
142	        }
143	    }
144	    let seq_len = args[0].data()[0];
145	    let d_model = args[1].data()[0];
146	    if seq_len < 0.0 || seq_len.fract() != 0.0 {
147	        return Err(RuntimeError::InvalidArgument {
148	            func: name.into(),
149	            reason: format!("seq_len must be a non-negative integer, got {seq_len}"),
150	        });
151	    }
152	    if d_model <= 0.0 || d_model.fract() != 0.0 {
153	        return Err(RuntimeError::InvalidArgument {
154	            func: name.into(),
155	            reason: format!("d_model must be a positive integer, got {d_model}"),
156	        });
157	    }
158	    Ok((seq_len as usize, d_model as usize))
159	}
