15	/// Evaluate a program (list of statements). Returns the last result as an array.
16	///
17	/// If the final value is a string, returns `EvalError::ExpectedArray`.
18	/// Use `eval_program_value` to handle both arrays and strings.
19	pub fn eval_program(stmts: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
20	    eval_program_value(stmts, env)?.into_array()
21	}
22	
23	/// Evaluate a program and return the final value (array or string).
24	pub fn eval_program_value(stmts: &[Expr], env: &mut Environment) -> Result<Value, EvalError> {
25	    run_program(stmts, env, None)
26	}
