52	pub(crate) fn eval_expr(
53	    expr: &Expr,
54	    env: &mut Environment,
55	    trace: &mut Option<&mut Trace>,
56	) -> Result<Value, EvalError> {
57	    if let Expr::StrLit(s, _) = expr {
58	        return Ok(Value::Str(s.clone()));
59	    }
60	    if let Expr::Ident(name, _) = expr
61	        && let Some(s) = env.get_string(name)
62	    {
63	        return Ok(Value::Str(s.clone()));
64	    }
65	    if let Expr::FnCall { name, args, .. } = expr
66	        && name == "svg"
67	    {
68	        return eval_svg(args, env, trace).map(Value::Str);
69	    }
70	    if let Expr::FnCall { name, args, span } = expr
71	        && name == "grad"
72	    {
73	        let result = crate::grad::eval_grad(args, env)?;
74	        if let Some(t) = trace.as_mut() {
75	            let seq = t.events().len() as u64;
76	            t.push(TraceEvent {
77	                seq,
78	                op: "grad".into(),
79	                span: *span,
80	                inputs: vec![],
81	                output: TraceValue::from_array(&result),
82	            });
83	        }
84	        return Ok(Value::Array(result));
85	    }
86	    if let Expr::FnCall { name, args, .. } = expr {
87	        // Model-constructor dispatch -- each builds a ModelSpec from
88	        // its args and returns Value::Model. Kept as a single match so
89	        // the eval entrypoint stays under its file LOC budget.
