fn eval_tensor_fncall(
    name: &str,
    args: &[Expr],
    env: &mut Environment,
    tape: &Rc<Tape>,
    params: &HashMap<String, Tensor>,
) -> Result<Tensor, EvalError> {
    let arity = |expected: usize| -> Result<(), EvalError> {
        if args.len() == expected {
            Ok(())
        } else {
            Err(EvalError::BadArity {
                func: name.into(),
                expected,
                got: args.len(),
            })
        }
    };
    if let Some(op) = unary_tensor_op(name) {
        arity(1)?;
        let a = eval_tensor_expr(&args[0], env, tape, params)?;
        return Ok(op(&a));
    }
    if name == "matmul" {
        arity(2)?;
        let a = eval_tensor_expr(&args[0], env, tape, params)?;
        let b = eval_tensor_expr(&args[1], env, tape, params)?;
        return Ok(a.matmul(&b));
    }
    if name == "apply" {
        arity(2)?;
        let model_name = match &args[0] {
            Expr::Ident(n, _) => n.clone(),
            _ => {
                return Err(EvalError::Unsupported(
                    "grad: apply's first argument must be a model identifier".into(),
                ));
            }
        };
        let model = env
            .get_model(&model_name)
            .cloned()
            .ok_or(EvalError::UndefinedVariable(model_name))?;
        let x = eval_tensor_expr(&args[1], env, tape, params)?;
        return crate::model_tape::apply_model_tape(&model, x, tape, params);
    }
    if name == "cross_entropy" {
        arity(2)?;
        let logits = eval_tensor_expr(&args[0], env, tape, params)?;
        let t_arr = crate::eval::eval_expr(&args[1], env, &mut None)?.into_array()?;
        let idx = crate::model_tape::validate_cross_entropy_targets(&logits.value(), &t_arr)?;
        return Ok(logits.cross_entropy(idx));
    }
    Err(EvalError::Unsupported(format!(
        "grad: function '{name}' not supported inside grad()"
    )))
}

